# ── 1b: Helpers — load and flatten any benchmark results JSON ────────────────
def load_results_json(path):
    """Load a benchmark results JSON. Returns (data, error_str)."""
    if not path.exists():
        return None, f'File not found: {path}'
    try:
        with open(path) as f:
            return json.load(f), None
    except Exception as e:
        return None, str(e)


def extract_all_cases(data):
    """Flatten benchmark JSON into a tidy DataFrame."""
    rows = []
    for case in data.get('cases', []):
        name = case.get('test_case', '')
        intractable = case.get('extrapolation_intractable', False)
        for method_key, mdata in case.get('results', {}).items():
            if not isinstance(mdata, dict):
                continue
            rows.append({
                'case':          name,
                'difficulty':    case.get('difficulty', ''),
                'formula_type':  case.get('formula_type', ''),
                'intractable':   intractable,
                'method':        method_key,
                'train_r2':      mdata.get('train_r2'),
                'test_r2':       mdata.get('test_r2'),
                'success':       mdata.get('success', False),
                'decision':      mdata.get('decision', ''),
                'instability':   mdata.get('instability'),
                'time_s':        mdata.get('time_s'),
                'predicted_formula': str(mdata.get('predicted_formula', ''))[:80],
            })
    return pd.DataFrame(rows)


